/**
 * PDF → PNG — n8n service client (Run Once for All Items)
 * Reads scale/pages/pdfName from the previous Set node, finds the PDF binary,
 * sends it (base64) to the conversion service, and returns ONLY one PNG per page.
 * Handles: missing/empty PDF, Render cold start (1 retry), HTTP errors,
 * invalid responses and broken page images — without crashing the run.
 */

const API = 'https://pdf-to-png-service-i3sb.onrender.com'; // no trailing slash

// ── Read settings from the Set node (safe defaults) ───────────────────
const cfg = $input.first()?.json ?? {};
const SCALE = Math.min(1, Math.max(0.1, Number(cfg.scale) || 1));
const PAGES = (cfg.pages ?? 'all').toString().trim() || 'all';
const WANT_RAW = (cfg.pdfName ?? '').toString().trim();
const WANT = WANT_RAW.toLowerCase();

// Pick the binary property holding the PDF.
// Priority: exact binary key (e.g. "data0") → file name → mime → .pdf → first.
const findPdfProp = (binary) => {
  const keys = Object.keys(binary || {});
  if (!keys.length) return null;
  if (WANT_RAW) {
    if (keys.includes(WANT_RAW)) return WANT_RAW;
    const named = keys.find((k) => (binary[k].fileName || '').toLowerCase() === WANT);
    if (named) return named;
  }
  return (
    keys.find((k) => (binary[k].mimeType || '').toLowerCase().includes('pdf')) ||
    keys.find((k) => (binary[k].fileName || '').toLowerCase().endsWith('.pdf')) ||
    keys[0]
  );
};

// One call to the service.
const convert = (b64) =>
  this.helpers.httpRequest({
    method: 'POST',
    url: API + '/convert',
    json: true,
    body: { pdf: b64, format: 'json', scale: SCALE, page: PAGES },
    timeout: 120000, // allow Render cold start (~50s)
  });

const errItem = (i, err, fileName) => ({
  json: {
    ok: false,
    item: i,
    source_file: fileName || null,
    error: err.message,
    status: err.statusCode || err.httpCode || null,
    server_said: err.response?.body || err.cause?.error || null,
    hint: 'First call after idle can take ~50s (Render cold start); it was retried once. Run again if it still fails.',
  },
});

const items = $input.all();
const out = [];

for (let i = 0; i < items.length; i++) {
  const binary = items[i].binary;
  const prop = findPdfProp(binary);
  const fileName = prop ? (binary[prop].fileName || prop) : null;

  if (!prop) {
    out.push({ json: { ok: false, item: i, error: 'No PDF binary found on this item. Make sure a PDF reaches this node.' } });
    continue;
  }

  // Read bytes → base64.
  let b64;
  try {
    const buf = await this.helpers.getBinaryDataBuffer(i, prop);
    if (!buf?.length) throw new Error('PDF binary is empty (0 bytes).');
    b64 = buf.toString('base64');
  } catch (e) {
    out.push({ json: { ok: false, item: i, source_file: fileName, error: 'Could not read PDF bytes: ' + e.message } });
    continue;
  }

  // Call service, with one retry on transient / cold-start failures.
  let res;
  try {
    res = await convert(b64);
  } catch (err) {
    const status = err.statusCode || err.httpCode;
    const transient = !status || status >= 500 || status === 408 || status === 429;
    if (!transient) { out.push(errItem(i, err, fileName)); continue; }
    try {
      await new Promise((r) => setTimeout(r, 5000));
      res = await convert(b64);
    } catch (err2) {
      out.push(errItem(i, err2, fileName));
      continue;
    }
  }

  // Validate response.
  if (!res || !Array.isArray(res.pages) || !res.pages.length) {
    out.push({ json: { ok: false, item: i, source_file: fileName, error: 'Service responded but returned no pages.', server_said: res ?? null } });
    continue;
  }

  // Output: ONLY one PNG binary per page (no summary item).
  for (const p of res.pages) {
    try {
      const base64 = (p.dataUrl || '').split(',')[1];
      if (!base64) throw new Error('missing dataUrl');
      out.push({
        json: { page: p.index, width: p.width, height: p.height, source_file: fileName },
        binary: { data: await this.helpers.prepareBinaryData(Buffer.from(base64, 'base64'), `page-${p.index}.png`, 'image/png') },
      });
    } catch (e) {
      out.push({ json: { ok: false, page: p.index, source_file: fileName, error: 'Failed to decode PNG: ' + e.message } });
    }
  }
}

return out;
